import React, { useEffect, useCallback, useState } from "react"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "./../data"
import { GatsbyImage } from "gatsby-plugin-image"
import useAllImages from "../hooks/useAllImages"
import VideoPlayer from "./atoms/VideoPlayer"
import "./../css/modal.scss"

// Helper function to detect if file is a video
const isVideoFile = (url) => {
  if (!url || typeof url !== 'string') return false;
  const videoExtensions = ['.webm', '.mp4', '.mov', '.avi'];
  return videoExtensions.some(ext => url.toLowerCase().endsWith(ext));
};

export default function Modal({ closeModal, id, type = "project", totalItems = 0, onPrevious, onNext }) {
  const { language } = useLanguage();
  const [isClosing, setIsClosing] = useState(false);
  const { findImage } = useAllImages();

  // Determine which data to use based on the type
  let content;
  if (type === "project") content = data.projects[id];
  else if (type === "education") content = data.education[id];
  else if (type === "selectedProject") content = data.projectsCarouselItems[id];

  // Enhanced close function with animation
  const handleClose = useCallback(() => {
    setIsClosing(true);
    // Wait for animation to complete before actually closing
    setTimeout(() => {
      closeModal(false);
    }, 300); // Match the CSS animation duration
  }, [closeModal]);

  // Navigation handlers with useCallback to prevent re-renders
  const handlePrevious = useCallback(() => {
    if (onPrevious && id > 0) {
      onPrevious();
    }
  }, [onPrevious, id]);

  const handleNext = useCallback(() => {
    if (onNext && id < totalItems - 1) {
      onNext();
    }
  }, [onNext, id, totalItems]);

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'ArrowLeft') {
        e.preventDefault();
        handlePrevious();
      } else if (e.key === 'ArrowRight') {
        e.preventDefault();
        handleNext();
      } else if (e.key === 'Escape') {
        e.preventDefault();
        handleClose();
      }
    };

    try {
      document.addEventListener('keydown', handleKeyDown);
    } catch (error) {
      console.warn('Error adding keydown listener:', error);
    }

    return () => {
      // Safely remove event listener
      try {
        document.removeEventListener('keydown', handleKeyDown);
      } catch (error) {
        // Suppress any DOM manipulation errors
        console.warn('Error removing keydown listener:', error);
      }
    };
  }, [id, totalItems, handlePrevious, handleNext, handleClose]);

  useEffect(() => {
    // Simple approach: just disable scrolling without positioning tricks
    try {
      document.body.classList.add('modal-open');
    } catch (error) {
      // Suppress any DOM manipulation errors
      console.warn('Modal body class addition failed:', error);
    }

    // Clean up function to re-enable scrolling when modal is unmounted
    return () => {
      try {
        document.body.classList.remove('modal-open');
      } catch (error) {
        // Suppress any DOM manipulation errors
        console.warn('Modal body class removal failed:', error);
      }
    };
  }, []);

  // Determine image source
  const imageSource = content.workImg || content.imageSrc || content.media;

  return (
    <>
      <div
        className={`modalBackground ${isClosing ? 'closing' : ''}`}
        onClick={handleClose}
        onKeyDown={(e) => {
          if (e.key === 'Enter' || e.key === ' ') {
            handleClose();
          }
        }}
        role="button"
        tabIndex={0}
        aria-label="Close modal"
      ></div>
      <div className={`modalContainer ${isClosing ? 'closing' : ''}`}>
        <div className="titleCloseBtn">
          <button
            onClick={handleClose}
          >
            <h3>&#215;</h3>
          </button>
        </div>

        {/* Navigation arrows - desktop only */}
        {totalItems > 1 && (
          <>
            {/* Previous arrow */}
            {id > 0 && (
              <button
                className="modal-nav-btn modal-prev"
                onClick={handlePrevious}
                aria-label="Previous item"
              >
                <span>&#8249;</span>
              </button>
            )}

            {/* Next arrow */}
            {id < totalItems - 1 && (
              <button
                className="modal-nav-btn modal-next"
                onClick={handleNext}
                aria-label="Next item"
              >
                <span>&#8250;</span>
              </button>
            )}
          </>
        )}
        <div className="title">
          <h1>{type === "project" ? getText(content.position, language) : getText(content.title, language)}</h1>
          <h2>{type === "project" ? content.date : (content.subtitle ? getText(content.subtitle, language) : "")}</h2>
        </div>
        <div className="body">
          {(() => {
            // Check if mediaItems exists for before/after positioning
            // Resolve any filename strings in mediaItems to gatsbyImageData
            const rawMediaItems = content.mediaItems;
            const mediaItems = rawMediaItems ? rawMediaItems.map(item => {
              if (item.type === 'image' && typeof item.src === 'string') {
                return { ...item, src: findImage(item.src) };
              }
              return item;
            }) : rawMediaItems;

            const renderMediaItem = (item, index) => {
              const itemIsVideo = item.type === 'video' || isVideoFile(item.src);
              // Check if src is a gatsbyImageData object
              const isGatsbyImg = item.src && typeof item.src === 'object' && item.src.images;

              return (
                <div key={index} style={{ width: '100%', marginBottom: '1rem' }}>
                  {itemIsVideo ? (
                    <VideoPlayer
                      mp4={item.src}
                      webm={item.webm}
                      className="img-fluid modal-media"
                      style={{ marginBottom: '0.5rem', width: '100%', borderRadius: '8px' }}
                    />
                  ) : isGatsbyImg ? (
                    <GatsbyImage
                      image={item.src}
                      alt={item.caption ? getText(item.caption, language) : ''}
                      className="img-fluid modal-media"
                      style={{ marginBottom: '0.5rem' }}
                    />
                  ) : (
                    <img
                      src={item.src}
                      alt=""
                      className="img-fluid modal-media"
                      loading="lazy"
                      style={{ marginBottom: '0.5rem' }}
                    />
                  )}
                  {item.caption && (
                    <p style={{
                      fontFamily: '"Montserrat", sans-serif',
                      fontWeight: 400,
                      fontSize: '0.85rem',
                      color: 'var(--text-dark-secondary)',
                      textAlign: 'center',
                      margin: '0',
                      lineHeight: '1.4'
                    }}>
                      {getText(item.caption, language)}
                    </p>
                  )}
                </div>
              );
            };

            if (mediaItems && mediaItems.length > 0) {
              const beforeItems = mediaItems.filter(item => !item.position || item.position === 'before');
              const afterItems = mediaItems.filter(item => item.position === 'after');

              const textContent = (
                <>
                  {content.modalIntro && (
                    <p className="modal-intro" style={{ marginBottom: '15px', fontWeight: 'bold' }}>
                      {getText(content.modalIntro, language)}
                    </p>
                  )}
                  {content.modalType === 'paragraph' ? (
                    <div className="modal-paragraphs">
                      {(content.modalDetails || content.description).map((desc, idx) => (
                        <p key={idx} dangerouslySetInnerHTML={{ __html: getText(desc, language) }} style={{ marginBottom: '15px' }}></p>
                      ))}
                    </div>
                  ) : (
                    <ul>
                      {(content.modalDetails || content.description).map((desc, idx) => (
                        <li key={idx} dangerouslySetInnerHTML={{ __html: getText(desc, language) }}></li>
                      ))}
                    </ul>
                  )}
                </>
              );

              return (
                <>
                  {beforeItems.map(renderMediaItem)}
                  {textContent}
                  {afterItems.map(renderMediaItem)}
                </>
              );
            }

            // Fallback: original single-image behavior
            // Check if imageSource is a gatsbyImageData object
            const isGatsbyFallback = imageSource && typeof imageSource === 'object' && imageSource.images;

            return (
              <>
                {isVideoFile(imageSource) ? (
                  <VideoPlayer
                    mp4={imageSource}
                    className="img-fluid modal-media"
                  />
                ) : isGatsbyFallback ? (
                  <GatsbyImage
                    image={imageSource}
                    alt=""
                    className="img-fluid modal-media"
                  />
                ) : (
                  <img
                    src={imageSource}
                    alt=""
                    className="img-fluid modal-media"
                    loading="lazy"
                  />
                )}

                {content.modalIntro && (
                  <p className="modal-intro" style={{ marginBottom: '15px', fontWeight: 'bold' }}>
                    {getText(content.modalIntro, language)}
                  </p>
                )}

                {content.modalType === 'paragraph' ? (
                  <div className="modal-paragraphs">
                    {(content.modalDetails || content.description).map((desc, index) => (
                      <p key={index} dangerouslySetInnerHTML={{ __html: getText(desc, language) }} style={{ marginBottom: '15px' }}></p>
                    ))}
                  </div>
                ) : (
                  <ul>
                    {(content.modalDetails || content.description).map((desc, index) => (
                      <li key={index} dangerouslySetInnerHTML={{ __html: getText(desc, language) }}></li>
                    ))}
                  </ul>
                )}
              </>
            );
          })()}
        </div>
        {/* <div className="footer">
          <button onClick={() => closeModal(false)}>close</button>
        </div> */}
      </div>
    </>
  )
}
