import { useStaticQuery, graphql } from "gatsby"
import { getImage } from "gatsby-plugin-image"

/**
 * Custom hook that queries all raster images processed by gatsby-plugin-sharp.
 * Returns a `findImage(filename)` helper to look up a gatsbyImageData object
 * by filename (without extension).
 *
 * Usage:
 *   const { findImage } = useAllImages();
 *   const img = findImage("project_hero_render_day");
 *   // → returns gatsbyImageData with responsive srcset, blur placeholder, etc.
 */
const useAllImages = () => {
  const data = useStaticQuery(graphql`
    query AllImagesQuery {
      allFile(
        filter: {
          sourceInstanceName: { eq: "images" }
          extension: { in: ["jpg", "jpeg", "png", "webp"] }
        }
      ) {
        nodes {
          relativePath
          name
          childImageSharp {
            gatsbyImageData(
              layout: FULL_WIDTH
              placeholder: BLURRED
              formats: [AUTO, WEBP, AVIF]
              quality: 80
            )
          }
        }
      }
    }
  `)

  /**
   * Find a processed image by its filename (without extension).
   * Falls back to partial match on relativePath.
   * @param {string} filename - The image filename without extension
   * @returns {object|null} gatsbyImageData object or null
   */
  const findImage = (filename) => {
    if (!filename) return null

    const node = data.allFile.nodes.find(
      (n) => n.name === filename || n.relativePath.includes(filename)
    )

    if (!node || !node.childImageSharp) return null
    return getImage(node.childImageSharp.gatsbyImageData)
  }

  return { findImage, allImages: data.allFile.nodes }
}

export default useAllImages
