import React from "react"
import Fade from "./animations/Fade"
import { useLanguage } from "../contexts/LanguageContext"
import data, { getText } from "../data"

const Skills = () => {
  const { language } = useLanguage();
  return (
    <div className="section" id="skills">
      <div className="container">
        <Fade bottom cascade distance="20px">
          <h1>{getText(data.sections.skills, language)}</h1>
          <h3 className="section-subheading text-muted" style={{
            fontFamily: '"Droid Serif", "Helvetica Neue", Helvetica, Arial, sans-serif',
            fontStyle: 'italic',
            fontSize: '1rem',
            marginBottom: '40px',
            marginTop: '10px',
            textAlign: 'center'
          }}>
            {getText(data.skillsSubtitle, language)}
          </h3>
        </Fade>
        <div className="skills-wrapper">
          <div className="grid">
            <Fade bottom distance="20px">
              {data.skills.map((skill, index) => (
                <div key={index} className="skill-item">
                  <img src={skill.img} alt={skill.title} loading="lazy" />
                  <h3>{skill.title}</h3>
                  <p
                    className="text-muted"
                    style={{ textAlign: 'left', maxWidth: '300px', marginLeft: 'auto', marginRight: 'auto' }}
                    dangerouslySetInnerHTML={{ __html: skill.para }}
                  ></p>
                </div>
              ))}
            </Fade>
          </div>
        </div>
      </div>
    </div>
  )
}

export default Skills
